      category: 'Brand Identity',
      client: "Yummy Bake's Villa",
      image: 'https://images.unsplash.com/photo-1556910116-e220f7127371?auto=format&fit=crop&q=80&w=800',
      media: [
        { type: 'image', url: 'https://images.unsplash.com/photo-1556910116-e220f7127371?auto=format&fit=crop&q=80&w=1200' },
